portName = sys.argv[1]
# 1. Open serial port
port = serial.Serial(portName, 115200, timeout=15)
print("Open serial port " + portName)

print("Wait 30 seconds for radio to boot")
serial.timeout = 30

assert port.read(4) == b'\x02\x24\x00\x03'
port.write(b'\x02\x14\x00\x03')

time.sleep(0.05)

print("C7000 Init detected")
port.timeout = 0.1

print("Sending firmware");
firmwareBlockIndex = 0
while firmwareBlockIndex < 15:
    port.write(firmwareBytes[firmwareBlockIndex])
    assert port.read(4) == ACK_OK
    firmwareBlockIndex += 1

print("Firmware sent");

#probably tells the C7000 to jump run the application firmware that has just been uploaded
port.write(b'\x02\x1B\x7E\x03\x00\x01\x09\x74')

assert port.read(4) == b'\x02\x05\x00\x03'

#not sure if its actually necessary to wait one second now for the C7000 to reboot

time.sleep(0.5)

print("Request data")
with open(sys.argv[2], "wb") as backupFile:
    address = 0
    while address < 0x100000:
        print(hex(address))

        addressBytes = address.to_bytes(4,'big')
        checkValue = (addressBytes[0] + addressBytes[1] + addressBytes[2] + addressBytes[3])

        port.write(b'\x02\x17')
        port.write((checkValue % 0x100).to_bytes(1,'big'))
        port.write(b'\x03')
        port.write(addressBytes)
        
        data = port.read(4+256)
        
        assert data[:2] == b'\x02\x05'
        
        backupFile.write(data[4:])
        
        address = address + 0x100
